-- 1. 중도 해지 함수 수정 (원금 + 이자 반환 로직 적용)
CREATE OR REPLACE FUNCTION public.cancel_student_savings(
    p_user_id text,
    p_saving_id uuid
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_amount numeric;
    v_cancel_rate numeric;
    v_refund_amount numeric;
    v_account_id text;
    v_teacher_id uuid;
    v_product_name text;
    v_product_id_text text;
BEGIN
    -- 적금 내역 조회 (userId text 캐스팅 확인)
    SELECT amount, "productId"
    INTO v_amount, v_product_id_text
    FROM public.student_savings 
    WHERE "savingId" = p_saving_id AND "userId"::text = p_user_id::text;

    IF v_amount IS NULL THEN RAISE EXCEPTION '해지할 적금 내역을 찾을 수 없습니다.'; END IF;

    -- 상품 정보 조회
    SELECT "cancellationRate", name, teacher_id::uuid
    INTO v_cancel_rate, v_product_name, v_teacher_id
    FROM public.savings_products WHERE id::text = v_product_id_text::text;

    -- [수정 핵심] 환급액 = 원금 + (원금 * 해지이율)
    -- 교사 관리자에서 5%를 설정했다면 v_cancel_rate는 0.05이므로, 원금(1) + 이자(0.05) = 1.05배가 반환됩니다.
    v_refund_amount := floor(v_amount + (v_amount * v_cancel_rate));

    -- 환급할 학생 계좌 조회 (개인 계좌 우선)
    SELECT "accountId" INTO v_account_id FROM public.accounts WHERE "userId"::text = p_user_id::text
    ORDER BY (CASE WHEN account_type = 'personal' THEN 1 ELSE 2 END) ASC, created_at DESC LIMIT 1;

    -- 계좌에 원금과 이자 합산액 입금
    UPDATE public.accounts SET balance = balance + v_refund_amount WHERE "accountId" = v_account_id;

    -- 거래 기록 저장
    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, description, date, teacher_id)
    VALUES (gen_random_uuid(), v_account_id, 'SavingsCancel', v_refund_amount, v_product_name || ' 중도해지 환급(원금포함)', now(), v_teacher_id);

    -- 적금 데이터 삭제
    DELETE FROM public.student_savings WHERE "savingId" = p_saving_id;

    RETURN v_product_name || ' 해지 완료 (' || v_refund_amount || ' 입금됨)';
END;
$$;

-- 2. 만기 처리 함수 생성/수정 (원금 + 이자 정산 로직)
CREATE OR REPLACE FUNCTION public.process_savings_maturity(
    p_user_id text,
    p_saving_id uuid
)
RETURNS text
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
    v_amount numeric;
    v_rate numeric;
    v_total_payout numeric;
    v_account_id text;
    v_teacher_id uuid;
    v_product_name text;
    v_product_id_text text;
BEGIN
    SELECT amount, "productId" INTO v_amount, v_product_id_text
    FROM public.student_savings 
    WHERE "savingId" = p_saving_id AND "userId"::text = p_user_id::text;

    IF v_amount IS NULL THEN RAISE EXCEPTION '만기 정산할 내역을 찾을 수 없습니다.'; END IF;

    SELECT rate, name, teacher_id::uuid INTO v_rate, v_product_name, v_teacher_id
    FROM public.savings_products WHERE id::text = v_product_id_text::text;

    -- [수정 핵심] 만기 수령액 = 원금 + (원금 * 이자율)
    v_total_payout := floor(v_amount + (v_amount * v_rate));

    SELECT "accountId" INTO v_account_id FROM public.accounts WHERE "userId"::text = p_user_id::text
    ORDER BY (CASE WHEN account_type = 'personal' THEN 1 ELSE 2 END) ASC, created_at DESC LIMIT 1;

    UPDATE public.accounts SET balance = balance + v_total_payout WHERE "accountId" = v_account_id;

    INSERT INTO public.transactions ("transactionId", "accountId", type, amount, description, date, teacher_id)
    VALUES (gen_random_uuid(), v_account_id, 'SavingsMaturity', v_total_payout, v_product_name || ' 만기 정산(원금+이자)', now(), v_teacher_id);

    DELETE FROM public.student_savings WHERE "savingId" = p_saving_id;

    RETURN v_product_name || ' 만기 정산 완료 (' || v_total_payout || ' 입금됨)';
END;
$$;

