                        {loading ? '처리 중...' : '확정하기'}
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="absolute inset-0 bg-white z-[110] flex flex-col animate-fadeIn rounded-[40px]">
            <div className="flex-grow overflow-y-auto p-8 pt-16 flex flex-col items-center">
