                                    </div>
                                    <div className="text-right">
                                        <div className="text-[10px] text-gray-700 font-black uppercase mb-1">평가금액</div>
                                        <div className="font-black text-2xl text-gray-900">{currentVal.toLocaleString()}{unit}</div>
                                    </div>
                                </div>
